DnaXmlFormat_pimpl::DnaXmlFormat_pimpl(std::ifstream* is, PUINT32 clusterID, const std::string& referenceframe, const std::string& epoch, 
	bool firstFile, 
	bool userspecifiedreferenceframe, bool userspecifiedepoch,
	bool overridereferenceframe)
{
	// capture pointer to file stream
	is_ = is;
	
	// capture global cluster ID to permit sequential numbering over several input files
	_clusterID = *clusterID;	

	// capture default reference frame and epoch
	_referenceframe = referenceframe;
	_epoch = epoch;

	// Initialise file EPSG and epoch from the default reference frame.
	// Previously these were set by the XSD attribute defaults during
	// validation.  With dont_validate, the attribute parsers are only
	// called when the attributes are present in the XML, so we need
	// sensible fallbacks.
	try {
		_fileEpsg = epsgStringFromName<std::string>(_referenceframe);
	}
	catch (...) {
		_fileEpsg.clear();
	}
	_fileEpoch = epoch;

	// capture first file flag
	_firstFile = firstFile;

	// Has the user supplied a reference frame and should this be used to override all?
	_userspecifiedreferenceframe = userspecifiedreferenceframe;
	_filespecifiedreferenceframe = false;
	_filespecifiedepoch = false;
	_overridereferenceframe = overridereferenceframe;
	_userspecifiedepoch = userspecifiedepoch;
}

void DnaXmlFormat_pimpl::pre()
{
	_pStns = new vdnaStnPtr ;
	_pMsrs = new vdnaMsrPtr ;

	g_parsemsr_tally.initialise();
	g_parsestn_tally.initialise();
	_station_count = 0;
	_measurement_count = 0;
}

void DnaXmlFormat_pimpl::DnaStation()
{
	_station_count++;
}

